
(function() {
    class EmbeddedProject extends HTMLElement {
        constructor() {
            super();
            this.attachShadow({mode: 'open'});
        }

        connectedCallback() {
            const shadow = this.shadowRoot;
            const decodeB64 = (str) => {
                try {
                    const binary = atob(str);
                    try { return decodeURIComponent(escape(binary)); } catch (e) { return binary; }
                } catch (e) { return ""; }
            };

            // 1. Inject External CSS
            ["https://fonts.googleapis.com/css?family=Open+Sans:300,300i,400,400i,600,600i,700,700i|Raleway:300,300i,400,400i,500,500i,600,600i,700,700i|Poppins:300,300i,400,400i,500,500i,600,600i,700,700i"].forEach(href => {
                const link = document.createElement('link');
                link.rel = 'stylesheet'; link.href = href;
                shadow.appendChild(link);
            });

            // 2. Inject Internal Styles
            const style = document.createElement('style');
            style.textContent = `:host { display: block; width: 100%; min-height: 100px; } .shadow-body { width: 100%; display: block; position: relative; } ` + decodeB64("");
            shadow.appendChild(style);
            
            // 3. Inject HTML
            const container = document.createElement('div');
            container.id = 'embedded-container';
            container.className = "shadow-body " + "";
            container.setAttribute('style', "");
            container.innerHTML = decodeB64("");
            shadow.appendChild(container);

            // 4. Load Scripts
            const extJs = [];
            const loadScripts = async () => {
                for (const src of extJs) {
                    await new Promise((resolve) => {
                        const s = document.createElement('script');
                        s.src = src; s.onload = resolve; s.onerror = resolve;
                        shadow.appendChild(s);
                    });
                }
                
                const jsCode = decodeB64("");
                if (jsCode.trim()) {
                    const isModule = /^\s*(import|export)\s+/m.test(jsCode) || jsCode.includes('import.meta');
                    const script = document.createElement('script');
                    if (isModule) {
                        const blob = new Blob([jsCode], { type: 'text/javascript' });
                        script.type = 'module'; script.src = URL.createObjectURL(blob);
                    } else {
                        script.textContent = `(function(document, shadowRoot){ ${jsCode} })(new Proxy(window.document, {
                            get(t, p) {
                                if (p === 'getElementById') return (id) => shadowRoot.getElementById(id);
                                if (p === 'querySelector') return (s) => shadowRoot.querySelector(s);
                                if (p === 'querySelectorAll') return (s) => shadowRoot.querySelectorAll(s);
                                if (p === 'getElementsByClassName') return (c) => shadowRoot.querySelectorAll("." + c);
                                if (p === 'getElementsByTagName') return (t) => shadowRoot.querySelectorAll(t);
                                let v = t[p]; return typeof v === 'function' ? v.bind(t) : v;
                            }
                        }), document.currentScript.getRootNode());`;
                    }
                    shadow.appendChild(script);
                }
            };
            loadScripts().then(() => {
                setTimeout(() => {
                    window.dispatchEvent(new Event('load'));
                    if (window.Webflow) { window.Webflow.ready(); try { window.Webflow.require('ix2').init(); } catch (e) {} }
                }, 100);
            });
        }
    }
    if (!customElements.get('embedded-project')) customElements.define('embedded-project', EmbeddedProject);
})();
